    expired: expired ?? defaultExpired,
    canSpotTrade: canSpotTrade ?? true,
    canPerpTrade: canPerpTrade ?? true,
    canWithdraw: canWithdraw ?? false,
    ...builder ? { builder } : {},
    ...maxFeeRate ? { maxFeeRate } : {},
